def chart_character_attack_heatmap(df: pd.DataFrame) -> go.Figure:
  pivot = df.pivot_table(
    index=CHARACTER_COL,
    columns=ATTACK_COL,
    values=SCORE_COL,
    aggfunc="mean",
  )

  # Weakest characters first, based on average robustness.
  order = (
    df.groupby(CHARACTER_COL)[SCORE_COL]
    .mean()
    .sort_values(ascending=True)
    .index.tolist()
  )
  pivot = pivot.reindex(order)

  return heatmap_from_pivot(
    pivot=pivot,
    title="Character × Attack Robustness Heatmap",
    x_label="Attack",
    y_label="Character",
    height=max(620, min(1800, 28 * len(pivot.index))),
  )


def chart_tested_value_attack_heatmaps(df: pd.DataFrame) -> list[tuple[str, go.Figure]]:
  charts = []

  for attack_trait in sorted(df[ATTACK_TRAIT_COL].dropna().unique()):
    value_col = resolve_tested_value_column(df, attack_trait)
    if value_col is None:
      continue

    sub = df[df[ATTACK_TRAIT_COL] == attack_trait].copy()
    if sub.empty:
      continue

    sub[value_col] = sub[value_col].fillna("Unknown").astype(str)

    pivot = sub.pivot_table(
      index=value_col,
      columns=ATTACK_COL,
      values=SCORE_COL,
      aggfunc="mean",
    )

    order = (
      sub.groupby(value_col)[SCORE_COL]
      .mean()
      .sort_values(ascending=True)
      .index.tolist()
    )
    pivot = pivot.reindex(order)

    fig = heatmap_from_pivot(
      pivot=pivot,
      title=f"Tested Value × Attack Robustness Heatmap: {pretty_label(attack_trait)}",
      x_label="Attack",
      y_label="Tested Value",
      height=max(520, min(1600, 42 * len(pivot.index))),
    )
    charts.append((f"Tested Value × Attack — {pretty_label(attack_trait)}", fig))

  return charts


def chart_always_never_rule_bar(df: pd.DataFrame) -> go.Figure:
  group_cols = [ATTACK_COL]
  if ATTACK_GROUP_COL in df.columns:
    group_cols.append(ATTACK_GROUP_COL)

  metrics = (
    df.groupby(group_cols, as_index=False)
    .agg(
      always_score=(ALWAYS_SCORE_COL, "mean"),
      never_score=(NEVER_SCORE_COL, "mean"),
      total_score=(SCORE_COL, "mean"),
    )
    .sort_values("total_score", ascending=True)
  )

  id_vars = [ATTACK_COL, "total_score"]
  if ATTACK_GROUP_COL in metrics.columns:
    id_vars.append(ATTACK_GROUP_COL)

  long = metrics.melt(
    id_vars=id_vars,
    value_vars=["always_score", "never_score"],
    var_name="rule_type",
    value_name="score",
  )
  long["rule_type"] = long["rule_type"].map(
    {
      "always_score": "Always-rule robustness",
      "never_score": "Never-rule robustness",
    }
  )

  fig = px.bar(
    long,
    x=ATTACK_COL,
    y="score",
    color="rule_type",
    barmode="group",
    category_orders={ATTACK_COL: metrics[ATTACK_COL].tolist()},
    hover_data=[ATTACK_GROUP_COL] if ATTACK_GROUP_COL in long.columns else None,
    labels={
      ATTACK_COL: "Attack",
      "score": "Rule-Type Robustness (%)",
      "rule_type": "Rule Type",
      ATTACK_GROUP_COL: "Attack Group",
    },
  )
  fig.update_yaxes(range=[0, 100], dtick=20, ticksuffix="%")
  fig.update_xaxes(tickangle=45)
  return style_fig(
    fig,
    title="Always vs Never Rule Robustness by Attack",
    height=620,
    width=width_for_categories(metrics[ATTACK_COL].nunique(), per_category_px=62),
  )


