def chart_character_trait_effect_strength(df: pd.DataFrame) -> go.Figure:
  rows = []

  for col in CHARACTER_TRAIT_COLS:
    if col not in df.columns:
      continue

    grouped = (
      df.groupby(col, dropna=False)
      .agg(average_robustness=(SCORE_COL, "mean"))
      .reset_index()
    )

    if len(grouped) <= 1:
      effect_strength = 0.0
      weakest_value = "N/A"
      strongest_value = "N/A"
    else:
      weakest = grouped.loc[grouped["average_robustness"].idxmin()]
      strongest = grouped.loc[grouped["average_robustness"].idxmax()]
      weakest_score = float(cast(float, weakest["average_robustness"]))
      strongest_score = float(cast(float, strongest["average_robustness"]))

      effect_strength = strongest_score - weakest_score
      weakest_value = str(weakest[col])
      strongest_value = str(strongest[col])

    rows.append(
      {
        "trait": pretty_label(col),
        "effect_strength": effect_strength,
        "value_count": int(df[col].nunique(dropna=False)),
        "weakest_value": weakest_value,
        "strongest_value": strongest_value,
      }
    )

  metrics = pd.DataFrame(rows).sort_values("effect_strength", ascending=True)

  fig = px.bar(
    metrics,
    x="effect_strength",
    y="trait",
    orientation="h",
    hover_data={
      "value_count": True,
      "weakest_value": True,
      "strongest_value": True,
      "effect_strength": ":.2f",
    },
    labels={
      "effect_strength": "Effect Strength",
      "trait": "Character Trait",
      "value_count": "Distinct Values",
      "weakest_value": "Lowest-Scoring Value",
      "strongest_value": "Highest-Scoring Value",
    },
  )
  return style_fig(
    fig, title="Character Trait Effect Strength", height=max(430, 34 * len(metrics))
  )


def lowest_robustness_cases_table(df: pd.DataFrame, top_n: int = 30) -> str:
  table_df = df.copy()

  def tested_value_for_row(row: pd.Series) -> str:
    value_col = resolve_tested_value_column(table_df, str(row[ATTACK_TRAIT_COL]))
    if value_col is None:
      return "Unknown"
    return str(row.get(value_col, "Unknown"))

  table_df["tested_value"] = table_df.apply(tested_value_for_row, axis=1)

  sort_cols = [SCORE_COL]
  ascending = [True]
  if ALWAYS_SCORE_COL in table_df.columns:
    sort_cols.append(ALWAYS_SCORE_COL)
    ascending.append(True)
  if NEVER_SCORE_COL in table_df.columns:
    sort_cols.append(NEVER_SCORE_COL)
    ascending.append(True)

  cases = table_df.sort_values(sort_cols, ascending=ascending).head(top_n)

  headers = [
    "Character",
    "Attack",
    "Attack Group",
    "Target Trait",
    "Tested Value",
    "Robustness",
    "Always Rules",
    "Never Rules",
    "Persona Model",
    "Attacker Model",
    "Transcript ID",
  ]

  rows = []
  for _, row in cases.iterrows():
    transcript_id = row.get("results.transcript_id", "")
    rows.append(
      "<tr>"
      f"<td>{escape_html(row.get(CHARACTER_COL, ''))}</td>"
      f"<td>{escape_html(row.get(ATTACK_COL, ''))}</td>"
      f"<td>{escape_html(row.get(ATTACK_GROUP_COL, 'Ungrouped'))}</td>"
      f"<td>{escape_html(row.get(ATTACK_TRAIT_COL, ''))}</td>"
      f"<td>{escape_html(row.get('tested_value', 'Unknown'))}</td>"
      f"<td><strong>{float(row.get(SCORE_COL, 0)):.1f}%</strong></td>"
      f"<td>{float(row.get(ALWAYS_SCORE_COL, 0)):.1f}%</td>"
      f"<td>{float(row.get(NEVER_SCORE_COL, 0)):.1f}%</td>"
      f"<td>{escape_html(row.get('results.persona_llm', ''))}</td>"
      f"<td>{escape_html(row.get('results.attacker_llm', ''))}</td>"
      f"<td><code>{escape_html(transcript_id)}</code></td>"
      "</tr>"
    )

  header_html = "".join(f"<th>{escape_html(header)}</th>" for header in headers)
  body_html = "".join(rows)

  return f"""
    <div class="table-intro">
      These are the concrete evaluation rows with the lowest robustness scores. Start here when you need transcripts or examples to inspect manually.
    </div>
    <div class="table-wrap">
      <table class="data-table">
        <thead><tr>{header_html}</tr></thead>
        <tbody>{body_html}</tbody>
      </table>
    </div>
    """


