def chart_feature_importance(df: pd.DataFrame) -> go.Figure:
  """
  Model-based feature importance, with graceful fallbacks.

  Tries sklearn RandomForestRegressor if available.
  If sklearn is unavailable, falls back to simple one-way effect strength:
      mean absolute deviation of category means from the global mean
  """
  # Intentionally exclude attack identity and target trait from this model.
  # Those are experimental conditions and tend to dominate the importance plot.
  # This chart is meant to show character-trait explanatory factors.
  feature_cols = [col for col in CHARACTER_TRAIT_COLS if col in df.columns]

  model_df = df[feature_cols + [SCORE_COL]].dropna().copy()

  # Keep the model-based feature-importance step responsive on large CSVs.
  # The fallback below still uses the full dataset if sklearn is unavailable.
  if len(model_df) > 5000:
    model_sample = model_df.sample(n=5000, random_state=42)
  else:
    model_sample = model_df

  try:
    from sklearn.compose import ColumnTransformer
    from sklearn.ensemble import RandomForestRegressor
    from sklearn.inspection import permutation_importance
    from sklearn.pipeline import Pipeline
    from sklearn.preprocessing import OneHotEncoder

    X = model_sample[feature_cols]
    y = model_sample[SCORE_COL]

    preprocessor = ColumnTransformer(
      transformers=[
        (
          "categorical",
          OneHotEncoder(handle_unknown="ignore"),
          feature_cols,
        )
      ]
    )

    model = RandomForestRegressor(
      n_estimators=100,
      random_state=42,
      min_samples_leaf=2,
      n_jobs=1,
    )

    pipeline = Pipeline(
      steps=[
        ("preprocessor", preprocessor),
        ("model", model),
      ]
    )

    pipeline.fit(X, y)

    result = permutation_importance(
      pipeline,
      X,
      y,
      n_repeats=3,
      random_state=42,
      n_jobs=1,
    )

    importances_mean = getattr(result, "importances_mean")

    importance = pd.DataFrame(
      {
        "feature": feature_cols,
        "importance": importances_mean,
      }
    ).sort_values("importance", ascending=False)

    method = "Permutation importance from RandomForestRegressor"

  except Exception:
    rows = []
    global_mean = model_df[SCORE_COL].mean()

    for col in feature_cols:
      means = model_df.groupby(col)[SCORE_COL].mean()
      if len(means) <= 1:
        importance = 0
      else:
        importance = float((means - global_mean).abs().mean())
      rows.append({"feature": col, "importance": importance})

    importance = pd.DataFrame(rows).sort_values("importance", ascending=False)
    method = "Fallback one-way mean effect strength"

  importance["feature_label"] = importance["feature"].map(pretty_label)

  fig = px.bar(
    importance.head(25).sort_values("importance", ascending=True),
    x="importance",
    y="feature_label",
    orientation="h",
    labels={
      "importance": "Importance",
      "feature_label": "Feature",
    },
    title=f"Feature Importance ({method})",
  )

  return style_fig(fig, title=None, height=max(520, 26 * min(len(importance), 25)))


