def fig_to_html(fig: go.Figure, div_id: str) -> str:
  return fig.to_html(
    include_plotlyjs=False,
    full_html=False,
    div_id=div_id,
    config={
      "responsive": True,
      "displaylogo": False,
      "modeBarButtonsToRemove": ["toImage"],
    },
  )


def slugify(text: str) -> str:
  text = text.lower()
  chars = []
  for ch in text:
    if ch.isalnum():
      chars.append(ch)
    elif ch in {" ", "-", "_", "—", ":"}:
      chars.append("-")
  slug = "".join(chars)
  while "--" in slug:
    slug = slug.replace("--", "-")
  return slug.strip("-") or "section"


def graph_card(
  title: str, note: str, fig: go.Figure, open_by_default: bool = False
) -> str:
  graph_id = slugify(title)
  plot_id = f"plot-{graph_id}"
  open_class = " open" if open_by_default else ""

  return f"""
    <div class="graph-card{open_class}" id="{graph_id}">
      <div class="graph-header" onclick="toggleGraph(this.parentElement)">
        <div class="graph-title-block">
          <h3>{escape_html(title)}</h3>
          <div class="note">{escape_html(note)}</div>
        </div>
        <div class="graph-actions" onclick="event.stopPropagation()">
          <button
            type="button"
            class="export-button"
            title="Export paper-style SVG"
            aria-label="Export paper-style SVG"
            onclick="downloadLightSVG(document.getElementById('{plot_id}'), '{graph_id}')"
          >
            <img src="{EXPORT_ICON_DATA_URI}" alt="" class="export-icon" />
          </button>
          <span class="chevron">▾</span>
        </div>
      </div>
      <div class="graph-content">
        {fig_to_html(fig, plot_id)}
      </div>
    </div>
    """


def html_card(title: str, note: str, html: str, open_by_default: bool = False) -> str:
  card_id = slugify(title)
  open_class = " open" if open_by_default else ""

  return f"""
    <div class="graph-card{open_class}" id="{card_id}">
      <div class="graph-header" onclick="toggleGraph(this.parentElement)">
        <div>
          <h3>{escape_html(title)}</h3>
          <div class="note">{escape_html(note)}</div>
        </div>
        <div class="graph-actions" onclick="event.stopPropagation()">
          <span class="chevron">▾</span>
        </div>
      </div>
      <div class="graph-content">
        {html}
      </div>
    </div>
    """


def family_section(
  title: str, subtitle: str, cards: list[str], open_by_default: bool = False
) -> str:
  section_id = slugify(title)
  open_class = " open" if open_by_default else ""

  return f"""
    <section class="family{open_class}" id="{section_id}">
      <div class="family-header" onclick="toggleFamily(this.parentElement)">
        <div>
          {escape_html(title)}
          <div class="family-subtitle">{escape_html(subtitle)}</div>
        </div>
        <span class="badge">{len(cards)}</span>
      </div>
      <div class="family-content">
        <div class="grid">
          {"".join(cards)}
        </div>
      </div>
    </section>
    """


def escape_html(text: object) -> str:
  return (
    str(text)
    .replace("&", "&amp;")
    .replace("<", "&lt;")
    .replace(">", "&gt;")
    .replace('"', "&quot;")
  )


def methodology_panel_html() -> str:
  return """
    <div class="methodology-grid">
      <div class="methodology-item">
        <div class="methodology-label">Robustness (%)</div>
        <p><strong>100%</strong> means the character broke no rules and the attack failed. <strong>0%</strong> means the character failed all evaluated rules.</p>
      </div>
      <div class="methodology-item">
        <div class="methodology-label">Always Rules</div>
        <p>Required behaviors the character should consistently maintain across responses.</p>
      </div>
      <div class="methodology-item">
        <div class="methodology-label">Never Rules</div>
        <p>Prohibited behaviors the character should avoid. Lower never-rule scores indicate stronger rule-breaking.</p>
      </div>
      <div class="methodology-item">
        <div class="methodology-label">Target Trait</div>
        <p>The character trait attacked in the evaluation, such as role, ancestry, ideal, or flaw.</p>
      </div>
      <div class="methodology-item">
        <div class="methodology-label">Tested Value</div>
        <p>The concrete value of the target trait, such as role = soldier or ancestry = dwarf.</p>
      </div>
      <div class="methodology-item">
        <div class="methodology-label">Scientific Use</div>
        <p>Use top sections for summary and failure discovery; use lower sections for chart export, trait analysis, and paper figures.</p>
      </div>
    </div>
    """


def build_dashboard_html(df: pd.DataFrame) -> str:
  unique_transcripts_count = len(df)

  if DUPLICATE_EVAL_COUNT_COL in df.columns:
    raw_evaluations_count = int(
      pd.to_numeric(
        df[DUPLICATE_EVAL_COUNT_COL],
        errors="coerce",
      )
      .fillna(1)
      .sum()
    )
  else:
    raw_evaluations_count = unique_transcripts_count

  characters_count = df[CHARACTER_COL].nunique()
  attacks_count = df[ATTACK_COL].nunique()
  traits_count = df[ATTACK_TRAIT_COL].nunique()
  avg_score = df[SCORE_COL].mean()
  perfect_rate = (df[SCORE_COL] >= 100).mean() * 100 if unique_transcripts_count else 0

  attack_means = df.groupby(ATTACK_COL)[SCORE_COL].mean().sort_values()
  trait_means = df.groupby(ATTACK_TRAIT_COL)[SCORE_COL].mean().sort_values()

  most_effective_attack = (
    str(attack_means.index[0]) if not attack_means.empty else "N/A"
  )
  _most_vulnerable_trait = str(trait_means.index[0]) if not trait_means.empty else "N/A"

  executive_summary_cards = [
    html_card(
      "How to Read This Dashboard",
      "Metric definitions and interpretation guide for internal debugging and paper-figure selection.",
      methodology_panel_html(),
      open_by_default=True,
    ),
    graph_card(
      "Attack Robustness Profile",
      "Combined attack map: average robustness, worst-case robustness, trait sensitivity, and score variability.",
      chart_attack_robustness_profile(df),
      open_by_default=True,
    ),
    graph_card(
      "Robustness (%) by Attack",
      "Distribution of robustness scores for each attack across all evaluated transcripts.",
      chart_overall_testscore_per_attack(df),
    ),
  ]

  vulnerability_hotspot_cards = [
    html_card(
      "Most Vulnerable Evaluation Cases",
      "Lowest-scoring concrete rows for manual transcript inspection and debugging.",
      lowest_robustness_cases_table(df),
      open_by_default=True,
    ),
  ]

  character_level_cards = [
    graph_card(
      "Character Average Robustness Distribution",
      "Number of characters falling into each explicitly labeled average robustness score bucket.",
      chart_character_robustness_distribution(df),
      open_by_default=True,
    ),
    graph_card(
      "Most Vulnerable Characters",
      "Characters with the lowest average robustness scores; useful when the character count grows.",
      chart_lowest_average_robustness_by_character(df),
      open_by_default=True,
    ),
    graph_card(
      "Worst-Case Robustness by Character",
      "Lowest observed robustness score for each character, with average score shown by color.",
      chart_worst_case_robustness_by_character(df),
    ),
  ]

  attack_group_cards = [
    graph_card(
      "Robustness (%) by Attack Group",
      "Distribution of robustness scores aggregated by the attack taxonomy group from attacks.py.",
      chart_attack_group_robustness(df),
      open_by_default=True,
    ),
    graph_card(
      "Attack Group × Target Trait Robustness Heatmap",
      "Average robustness for each attack group and target trait combination.",
      chart_attack_group_trait_heatmap(df),
      open_by_default=True,
    ),
  ]

  attack_trait_cards = [
    graph_card(
      "Most Effective Attacks",
      "Attacks with the lowest average robustness scores. Lower means the attack is more effective.",
      chart_lowest_average_robustness_by_attack(df),
      open_by_default=True,
    ),
    graph_card(
      "Target Trait Vulnerability Ranking",
      "Average robustness score for each attacked trait. Lower values indicate more vulnerable target areas.",
      chart_target_trait_ranking(df),
      open_by_default=True,
    ),
    graph_card(
      "Most Trait-Sensitive Attacks",
      "Attacks whose robustness changes most strongly depending on the targeted trait.",
      chart_most_trait_sensitive_attacks(df),
    ),
    *[
      graph_card(
        title,
        "For one target trait, robustness score distributions grouped by attack.",
        fig,
      )
      for title, fig in chart_variant_level_by_attack_trait(df)
    ],
  ]

  trait_value_representation_cards = [
    *[
      graph_card(
        title,
        "Counts unique characters for each value of this character trait; evaluation-row counts are included in hover text.",
        fig,
      )
      for title, fig in chart_trait_value_representation(df)
    ],
  ]

  tested_value_cards = [
    *[
      graph_card(
        title,
        "For one target trait, robustness score distributions grouped by the concrete tested value.",
        fig,
      )
      for title, fig in chart_resolved_variant_by_attack_trait(df)
    ],
  ]

  rule_type_cards = [
    graph_card(
      "Always vs Never Rule Robustness by Attack",
      "Compares whether attacks weaken required behaviors or prohibited behaviors more strongly.",
      chart_always_never_rule_bar(df),
      open_by_default=True,
    ),
    graph_card(
      "Attack Rule-Type Robustness Profile",
      "Each attack plotted by its average always-rule score and never-rule score.",
      chart_rule_type_profile_scatter(df),
    ),
  ]

  model_explanation_cards = [
    graph_card(
      "Character Trait Effect Strength",
      "How much robustness varies between values inside each character trait.",
      chart_character_trait_effect_strength(df),
    ),
    graph_card(
      "Feature Importance for Robustness",
      "Character-trait feature importance only; LLM columns, attack identity, and target trait are intentionally excluded.",
      chart_feature_importance(df),
    ),
  ]

  appendix_cards = [
    graph_card(
      "Appendix: Full Character × Attack Robustness Matrix",
      "Full lookup matrix of average robustness score for each character and attack pair.",
      chart_character_attack_heatmap(df),
    ),
    graph_card(
      "Appendix: Full Attack × Target Trait Robustness Matrix",
      "Full lookup matrix of average robustness score for each attack and targeted character trait pair.",
      chart_atk_x_attack_trait_heatmap(df),
    ),
    graph_card(
      "Appendix: Full Robustness (%) by Character",
      "Full character-level robustness distribution. Useful as a lookup view and for figure export.",
      chart_character_robustness(df),
    ),
    *[
      graph_card(
        f"Appendix: {title}",
        "For one target trait, average robustness score for each tested value and attack pair.",
        fig,
      )
      for title, fig in chart_tested_value_attack_heatmaps(df)
    ],
  ]

  section_specs = [
    (
      "Executive Summary",
      "Metric definitions and the primary attack-level overview.",
      executive_summary_cards,
      True,
    ),
    (
      "Vulnerability Hotspots",
      "Concrete low-scoring cases for transcript inspection and debugging.",
      vulnerability_hotspot_cards,
      True,
    ),
    (
      "Character Robustness",
      "Character-level summaries of average and worst-case robustness.",
      character_level_cards,
      False,
    ),
    (
      "Attack Group Diagnostics",
      "Attack taxonomy views based on the group metadata in attacks.py.",
      attack_group_cards,
      False,
    ),
    (
      "Attack and Target Trait Diagnostics",
      "Attack-level and target-trait views for identifying effective attacks and vulnerable targets.",
      attack_trait_cards,
      False,
    ),
    (
      "Rule-Type Diagnostics",
      "Required-behavior versus prohibited-behavior failures.",
      rule_type_cards,
      False,
    ),
    (
      "Trait-Value Representation",
      "Dataset coverage: how many unique characters instantiate each trait value.",
      trait_value_representation_cards,
      False,
    ),
    (
      "Tested Value Diagnostics",
      "Trait-value robustness views such as role=soldier or ancestry=dwarf.",
      tested_value_cards,
      False,
    ),
    (
      "Model Comparison and Explanation",
      "Model comparisons, character-trait effects, and feature-importance views.",
      model_explanation_cards,
      False,
    ),
    (
      "Appendices",
      "Full lookup matrices and larger reference views for exploration and figure export.",
      appendix_cards,
      False,
    ),
  ]

  sections = [
    family_section(title, subtitle, cards, open_by_default=open_by_default)
    for title, subtitle, cards, open_by_default in section_specs
  ]

  toc_items = [(title, slugify(title)) for title, _, _, _ in section_specs]

  toc_html = "".join(
    f'<a href="#{section_id}">{escape_html(label)}</a>'
    for label, section_id in toc_items
  )

  return f"""<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Character Robustness Evaluation Dashboard</title>
  <script src="https://cdn.plot.ly/plotly-2.35.2.min.js"></script>
  <style>
    :root {{
      --bg: #0b1020;
      --panel: #121933;
      --panel-2: #0f1530;
      --border: rgba(255,255,255,0.08);
      --text: #ecf1ff;
      --muted: #a8b2d1;
      --accent: #7aa2ff;
      --accent-2: #9ec0ff;
      --shadow: 0 16px 40px rgba(0,0,0,0.25);
      --radius: 20px;
    }}
    * {{ box-sizing: border-box; }}
    html {{ scroll-behavior: smooth; }}
    body {{
      margin: 0;
      font-family: Inter, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif;
      background: linear-gradient(180deg, #0a0f1d 0%, #111731 100%);
      color: var(--text);
    }}
    .app {{
      display: grid;
      grid-template-columns: 260px 1fr;
      min-height: 100vh;
    }}
    .sidebar {{
      position: sticky;
      top: 0;
      height: 100vh;
      overflow: auto;
      border-right: 1px solid var(--border);
      background: rgba(9, 13, 28, 0.96);
      padding: 18px 16px 28px;
    }}
    .sidebar h2 {{ margin: 0 0 8px; font-size: 18px; }}
    .small {{ color: var(--muted); font-size: 12px; margin-bottom: 14px; line-height: 1.45; }}
    .toc {{
      border: 1px solid var(--border);
      border-radius: 14px;
      background: rgba(255,255,255,0.02);
      padding: 10px 14px 12px;
    }}
    .toc a {{
      display: block;
      color: var(--accent-2);
      text-decoration: none;
      font-size: 13px;
      line-height: 1.5;
      padding: 5px 0;
    }}
    .sidebar-actions {{
      position: sticky;
      bottom: 0;
      background: linear-gradient(180deg, rgba(9,13,28,0) 0%, rgba(9,13,28,0.98) 24%);
      padding-top: 12px;
      margin-top: 14px;
    }}
    .sidebar-actions button {{
      width: 100%;
      border: 1px solid var(--border);
      background: var(--panel);
      color: var(--text);
      padding: 12px 14px;
      border-radius: 12px;
      cursor: pointer;
      margin-top: 8px;
      font-weight: 600;
    }}
    .main {{ padding: 24px 30px 36px; max-width: 1760px; width: 100%; margin: 0 auto; }}
    .hero {{
      display: grid;
      grid-template-columns: 1.8fr 1.2fr;
      gap: 14px;
      margin-bottom: 14px;
      align-items: start;
    }}
    .card {{
      background: linear-gradient(180deg, rgba(255,255,255,0.028), rgba(255,255,255,0.012));
      border: 1px solid var(--border);
      border-radius: 18px;
      padding: 16px 18px;
      box-shadow: 0 8px 24px rgba(0,0,0,0.16);
      backdrop-filter: blur(8px);
    }}
    h1 {{ font-size: 28px; line-height: 1.15; margin: 0 0 8px; letter-spacing: -0.02em; }}
    .subtitle {{ color: var(--muted); line-height: 1.5; margin: 0; font-size: 14px; max-width: 72ch; }}
    .kpis {{
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 10px;
      height: 100%;
      align-content: start;
    }}
    .kpi {{
      background: var(--panel-2);
      border: 1px solid var(--border);
      border-radius: 14px;
      padding: 12px 13px;
      min-height: 84px;
    }}
    .kpi .label {{
      color: var(--muted);
      font-size: 11px;
      text-transform: uppercase;
      letter-spacing: 0.07em;
    }}
    .kpi .value {{
      font-size: 24px;
      font-weight: 700;
      margin-top: 8px;
      line-height: 1.15;
    }}
    .kpi .value.text-value {{
      font-size: 17px;
      line-height: 1.25;
      overflow-wrap: anywhere;
    }}
    .methodology-grid {{
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 12px;
    }}
    .methodology-item {{
      border: 1px solid rgba(255,255,255,0.07);
      background: rgba(255,255,255,0.018);
      border-radius: 14px;
      padding: 14px;
    }}
    .methodology-label {{
      color: var(--accent-2);
      font-weight: 700;
      font-size: 13px;
      margin-bottom: 8px;
      text-transform: uppercase;
      letter-spacing: 0.05em;
    }}
    .methodology-item p {{
      color: #d9e3ff;
      margin: 0;
      line-height: 1.5;
      font-size: 13px;
    }}
    .table-intro {{
      color: var(--muted);
      font-size: 13px;
      line-height: 1.5;
      margin-bottom: 10px;
    }}
    .family {{
      margin: 18px 0;
      border: 1px solid var(--border);
      border-radius: 20px;
      overflow: hidden;
      background: rgba(255,255,255,0.02);
      box-shadow: var(--shadow);
    }}
    .family-header {{
      padding: 16px 18px;
      font-size: 22px;
      font-weight: 700;
      letter-spacing: -0.01em;
      cursor: pointer;
      background: rgba(255,255,255,0.03);
      display: flex;
      justify-content: space-between;
      align-items: center;
    }}
    .family-subtitle {{
      color: var(--muted);
      font-size: 13px;
      font-weight: 400;
      margin-top: 6px;
      max-width: 88ch;
    }}
    .family-content {{ display: none; padding: 18px; }}
    .family.open .family-content {{ display: block; }}
    .grid {{
      display: grid;
      grid-template-columns: repeat(12, 1fr);
      gap: 18px;
    }}
    .graph-card {{
      background: linear-gradient(180deg, rgba(255,255,255,0.018), rgba(255,255,255,0.009));
      border: 1px solid var(--border);
      border-radius: 18px;
      overflow: hidden;
      grid-column: span 12;
      box-shadow: 0 8px 22px rgba(0,0,0,0.14);
    }}
    .graph-header {{
      padding: 14px 16px;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
      background: rgba(255,255,255,0.025);
    }}
    .graph-header h3 {{ margin: 0; font-size: 18px; line-height: 1.2; letter-spacing: -0.01em; }}
    .graph-actions {{
      display: inline-flex;
      align-items: center;
      gap: 8px;
      flex-shrink: 0;
    }}
    .graph-title-block {{
      min-width: 0;
      flex: 1 1 auto;
    }}
    .export-button {{
      border: 1px solid rgba(255,255,255,0.10);
      background: rgba(255,255,255,0.04);
      color: var(--text);
      width: 36px;
      height: 36px;
      padding: 0;
      border-radius: 10px;
      cursor: pointer;
      display: inline-flex;
      align-items: center;
      justify-content: center;
    }}
    .export-button:hover {{
      border-color: rgba(255,255,255,0.22);
      background: rgba(255,255,255,0.08);
    }}
    .export-icon {{
      width: 18px;
      height: 18px;
      display: block;
      object-fit: contain;
      border-radius: 4px;
    }}
    .note {{ color: var(--muted); font-size: 12.5px; line-height: 1.45; margin-top: 5px; max-width: 78ch; }}
    .graph-content {{
      display: none;
      padding: 14px 16px 16px;
      overflow-x: auto;
      overflow-y: hidden;
    }}
    .graph-content .js-plotly-plot,
    .graph-content .plotly-graph-div {{
      flex: 0 0 auto;
    }}
    .graph-card.open .graph-content {{ display: block; }}
    .badge {{
      display: inline-flex;
      align-items: center;
      justify-content: center;
      min-width: 24px;
      height: 24px;
      border-radius: 999px;
      border: 1px solid var(--border);
      background: rgba(255,255,255,0.03);
      font-size: 12px;
      color: var(--muted);
      padding: 0 8px;
    }}
    .table-wrap {{
      overflow: auto;
      border: 1px solid var(--border);
      border-radius: 14px;
      background: rgba(255,255,255,0.015);
    }}
    .data-table {{
      width: 100%;
      border-collapse: collapse;
      font-size: 13px;
      min-width: 980px;
    }}
    .data-table th,
    .data-table td {{
      padding: 10px 12px;
      border-bottom: 1px solid rgba(255,255,255,0.06);
      text-align: left;
      vertical-align: top;
    }}
    .data-table th {{
      color: var(--text);
      background: rgba(255,255,255,0.04);
      position: sticky;
      top: 0;
      z-index: 1;
    }}
    .data-table td {{
      color: #d9e3ff;
    }}
    .data-table tr:hover td {{
      background: rgba(255,255,255,0.03);
    }}
    .footer {{
      color: var(--muted);
      font-size: 12px;
      margin-top: 24px;
      text-align: center;
    }}
    .fixed-boxplot-hover-enabled .hoverlayer .hovertext {{
      opacity: 0 !important;
      pointer-events: none !important;
    }}
    .fixed-boxplot-hover-box {{
      position: absolute;
      z-index: 1000;
      display: none;
      max-width: min(420px, calc(100% - 24px));
      padding: 10px 12px;
      border: 1px solid rgba(255,255,255,0.28);
      border-radius: 10px;
      background: rgba(18,24,44,0.96);
      color: #f4f6ff;
      font-size: 13px;
      line-height: 1.35;
      pointer-events: none;
      box-shadow: 0 10px 24px rgba(0,0,0,0.35);
    }}
    .fixed-boxplot-hover-box .hover-line {{
      white-space: normal;
      overflow-wrap: anywhere;
    }}
    @media (max-width: 1200px) {{
      .app {{ grid-template-columns: 1fr; }}
      .sidebar {{
        position: relative;
        height: auto;
        border-right: 0;
        border-bottom: 1px solid var(--border);
      }}
      .hero {{ grid-template-columns: 1fr; }}
      .kpis {{ grid-template-columns: repeat(2, minmax(0, 1fr)); }}
      .methodology-grid {{ grid-template-columns: 1fr; }}
    }}
  </style>
</head>
<body>
  <div class="app">
    <aside class="sidebar">
      <h2>Table of contents</h2>
      <div class="small">Internal exploration dashboard with paper-friendly export. The first two sections open by default; detailed diagnostics and full lookup views are collapsed for faster reading.</div>
      <div class="toc">{toc_html}</div>
      <div class="sidebar-actions">
        <button onclick="collapseAll()">Collapse all</button>
        <button onclick="expandAll()">Expand all</button>
      </div>
    </aside>

    <main class="main">
      <div class="hero">
        <div class="card">
          <h1>Character Robustness Evaluation Dashboard</h1>
          <p class="subtitle">
            Internal scientific/debugging dashboard for character robustness evaluation. Use the open sections for summary and failure discovery; use collapsed diagnostic sections and appendices for deeper exploration and figure export. Robustness is displayed as a percentage: 100% means the character broke no rules and the attack failed; 0% means the character failed all evaluated rules.
          </p>
        </div>
        <div class="kpis">
          <div class="kpi"><div class="label">Unique transcripts analyzed</div><div class="value">{unique_transcripts_count:,}</div></div>
            <div class="kpi"><div class="label">Raw evaluations loaded</div><div class="value">{raw_evaluations_count:,}</div></div>
            <div class="kpi"><div class="label">Avg robustness</div><div class="value">{avg_score:.1f}%</div></div>
            <div class="kpi"><div class="label">Perfect robustness rate</div><div class="value">{perfect_rate:.1f}%</div></div>
            <div class="kpi"><div class="label">Most effective attack</div><div class="value text-value">{escape_html(most_effective_attack)}</div></div>
            <div class="kpi"><div class="label">Characters / attacks</div><div class="value">{characters_count:,} / {attacks_count:,}</div></div></div>
      </div>

      {"".join(sections)}

      <div class="footer">
        Generated by build_dashboard.py. Traits observed: {traits_count}.
      </div>
    </main>
  </div>

  <script>
    const PAPER_EXPORT_FONT = "Arial, Helvetica, sans-serif";
    const PAPER_EXPORT_WIDTH = 1400;
    const PAPER_EXPORT_HEIGHT = 900;

    function deepClone(obj) {{
      return JSON.parse(JSON.stringify(obj || {{}}));
    }}

    function paperAxis(axis) {{
      const cloned = deepClone(axis);

      cloned.color = "black";
      cloned.linecolor = "black";
      cloned.mirror = true;
      cloned.ticks = "outside";
      cloned.tickcolor = "black";
      cloned.gridcolor = "rgba(0,0,0,0.14)";
      cloned.zerolinecolor = "rgba(0,0,0,0.28)";
      cloned.tickfont = {{
        ...(cloned.tickfont || {{}}),
        family: PAPER_EXPORT_FONT,
        color: "black",
        size: 12,
      }};

      if (cloned.title) {{
        cloned.title = {{
          ...cloned.title,
          font: {{
            ...(cloned.title.font || {{}}),
            family: PAPER_EXPORT_FONT,
            color: "black",
            size: 15,
          }},
        }};
      }}

      return cloned;
    }}

    function paperAnnotation(annotation) {{
      const cloned = deepClone(annotation);
      cloned.font = {{
        ...(cloned.font || {{}}),
        family: PAPER_EXPORT_FONT,
        color: "black",
        size: cloned.font?.size || 12,
      }};
      return cloned;
    }}

    function paperColorAxis(coloraxis) {{
      const cloned = deepClone(coloraxis);

      if (cloned.colorbar) {{
        cloned.colorbar = {{
          ...cloned.colorbar,
          outlinecolor: "rgba(0,0,0,0.35)",
          tickcolor: "black",
          tickfont: {{
            ...(cloned.colorbar.tickfont || {{}}),
            family: PAPER_EXPORT_FONT,
            color: "black",
            size: 12,
          }},
        }};

        if (cloned.colorbar.title) {{
          cloned.colorbar.title = {{
            ...cloned.colorbar.title,
            font: {{
              ...(cloned.colorbar.title.font || {{}}),
              family: PAPER_EXPORT_FONT,
              color: "black",
              size: 13,
            }},
          }};
        }}
      }}

      return cloned;
    }}

    function buildPaperLayout(layout) {{
      const paperLayout = {{
        paper_bgcolor: "white",
        plot_bgcolor: "white",
        font: {{
          ...(layout.font || {{}}),
          family: PAPER_EXPORT_FONT,
          color: "black",
          size: 13,
        }},
        margin: {{
          l: Math.max(layout.margin?.l || 80, 90),
          r: Math.max(layout.margin?.r || 40, 50),
          t: Math.max(layout.margin?.t || 70, 78),
          b: Math.max(layout.margin?.b || 80, 88),
        }},
      }};

      if (layout.title) {{
        paperLayout.title = {{
          ...deepClone(layout.title),
          font: {{
            ...(layout.title.font || {{}}),
            family: PAPER_EXPORT_FONT,
            color: "black",
            size: 20,
          }},
        }};
      }}

      for (const key of Object.keys(layout)) {{
        if (/^xaxis\\d*$/.test(key) || /^yaxis\\d*$/.test(key)) {{
          paperLayout[key] = paperAxis(layout[key]);
        }}

        if (/^scene\\d*$/.test(key)) {{
          const scene = deepClone(layout[key]);
          for (const axisKey of ["xaxis", "yaxis", "zaxis"]) {{
            if (scene[axisKey]) {{
              scene[axisKey] = paperAxis(scene[axisKey]);
            }}
          }}
          paperLayout[key] = scene;
        }}

        if (/^polar\\d*$/.test(key)) {{
          const polar = deepClone(layout[key]);
          if (polar.radialaxis) polar.radialaxis = paperAxis(polar.radialaxis);
          if (polar.angularaxis) polar.angularaxis = paperAxis(polar.angularaxis);
          paperLayout[key] = polar;
        }}

        if (/^coloraxis\\d*$/.test(key)) {{
          paperLayout[key] = paperColorAxis(layout[key]);
        }}
      }}

      if (Array.isArray(layout.annotations)) {{
        paperLayout.annotations = layout.annotations.map(paperAnnotation);
      }}

      if (layout.legend) {{
        paperLayout.legend = {{
          ...deepClone(layout.legend),
          font: {{
            ...(layout.legend.font || {{}}),
            family: PAPER_EXPORT_FONT,
            color: "black",
            size: 12,
          }},
          bgcolor: "white",
          bordercolor: "rgba(0,0,0,0.22)",
          borderwidth: 1,
        }};
      }}

      return paperLayout;
    }}

    function buildPaperTraceUpdates(plotDiv) {{
      const update = {{
        "textfont.color": [],
        "textfont.family": [],
        "textfont.size": [],
        "marker.line.color": [],
        "line.color": [],
      }};

      const traceIndexes = [];

      plotDiv.data.forEach((trace, index) => {{
        traceIndexes.push(index);
        update["textfont.color"].push("black");
        update["textfont.family"].push(PAPER_EXPORT_FONT);
        update["textfont.size"].push(12);

        // Do not override continuous heatmap/scatter marker colors; only outline where applicable.
        update["marker.line.color"].push("rgba(0,0,0,0.38)");

        // Keep trace line colors unless they are inherited from the dark theme.
        update["line.color"].push(trace.line?.color || null);
      }});

      return {{ update, traceIndexes }};
    }}

    async function downloadLightSVG(plotDiv, filename) {{
      if (!plotDiv) {{
        console.error("Could not find Plotly chart for export.");
        return;
      }}

      const originalLayout = deepClone(plotDiv.layout);
      const originalData = deepClone(plotDiv.data);
      const paperLayout = buildPaperLayout(plotDiv.layout);
      const {{ update, traceIndexes }} = buildPaperTraceUpdates(plotDiv);

      try {{
        await Plotly.relayout(plotDiv, paperLayout);
        await Plotly.restyle(plotDiv, update, traceIndexes);

        await Plotly.downloadImage(plotDiv, {{
          format: "svg",
          filename: filename,
          width: PAPER_EXPORT_WIDTH,
          height: PAPER_EXPORT_HEIGHT,
          scale: 1,
        }});
      }} finally {{
        await Plotly.react(plotDiv, originalData, originalLayout, plotDiv._context);
      }}
    }}

    function toggleFamily(el) {{
      el.classList.toggle("open");
      setTimeout(() => window.dispatchEvent(new Event("resize")), 50);
    }}

    function toggleGraph(el) {{
      el.classList.toggle("open");
      setTimeout(() => window.dispatchEvent(new Event("resize")), 50);
    }}

    function collapseAll() {{
      document.querySelectorAll(".family, .graph-card").forEach(el => el.classList.remove("open"));
    }}

    function expandAll() {{
      document.querySelectorAll(".family, .graph-card").forEach(el => el.classList.add("open"));
      setTimeout(() => window.dispatchEvent(new Event("resize")), 50);
    }}


    function escapeHtml(value) {{
      return String(value)
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#039;");
    }}

    function enableFixedHorizontalBoxplotHover() {{
      document.querySelectorAll(".js-plotly-plot").forEach((plot) => {{
        const traces = plot._fullData || plot.data || [];
        const isHorizontalBoxplot = traces.some((trace) => {{
          return trace.type === "box" && trace.orientation === "h";
        }});

        if (!isHorizontalBoxplot) {{
          return;
        }}

        plot.classList.add("fixed-boxplot-hover-enabled");

        const parent = plot.parentElement;
        parent.style.position = "relative";

        let box = parent.querySelector(".fixed-boxplot-hover-box");
        if (!box) {{
          box = document.createElement("div");
          box.className = "fixed-boxplot-hover-box";
          parent.appendChild(box);
        }}

        let mouse = {{ x: 18, y: 18 }};

        function updateMousePosition(event) {{
          const parentRect = parent.getBoundingClientRect();
          mouse = {{
            x: event.clientX - parentRect.left,
            y: event.clientY - parentRect.top,
          }};
        }}

        function positionBoxNearCursor() {{
          const padding = 12;
          const offset = 18;
          const parentRect = parent.getBoundingClientRect();

          box.style.display = "block";
          box.style.left = "0px";
          box.style.top = "0px";

          const boxRect = box.getBoundingClientRect();

          let left = mouse.x + offset;
          let top = mouse.y + offset;

          if (left + boxRect.width + padding > parentRect.width) {{
            left = mouse.x - boxRect.width - offset;
          }}
          if (top + boxRect.height + padding > parentRect.height) {{
            top = mouse.y - boxRect.height - offset;
          }}

          left = Math.max(padding, Math.min(left, parentRect.width - boxRect.width - padding));
          top = Math.max(padding, Math.min(top, parentRect.height - boxRect.height - padding));

          box.style.left = left + "px";
          box.style.top = top + "px";
        }}

        plot.addEventListener("mousemove", (event) => {{
          updateMousePosition(event);
          if (box.style.display === "block") {{
            positionBoxNearCursor();
          }}
        }});

        plot.on("plotly_hover", () => {{
          requestAnimationFrame(() => {{
            const hoverTexts = Array.from(
              plot.querySelectorAll(".hoverlayer .hovertext text")
            )
              .map((node) => node.textContent.trim())
              .filter(Boolean);

            if (hoverTexts.length === 0) {{
              box.style.display = "none";
              return;
            }}

            box.innerHTML = hoverTexts
              .map((line) => '<div class="hover-line">' + escapeHtml(line) + '</div>')
              .join("");

            positionBoxNearCursor();
          }});
        }});

        plot.on("plotly_unhover", () => {{
          box.style.display = "none";
        }});
      }});
    }}

    document.addEventListener("DOMContentLoaded", enableFixedHorizontalBoxplotHover);
  </script>
</body>
</html>
"""


def build_dashboard() -> None:
  df = read_data(INPUT_FILE)
  html = build_dashboard_html(df)
  OUTPUT_FILE.parent.mkdir(parents=True, exist_ok=True)
  OUTPUT_FILE.write_text(html, encoding="utf-8")


def main() -> None:
  build_dashboard()
  print(f"Read input from: {INPUT_FILE}")
  print(f"Wrote dashboard to: {OUTPUT_FILE}")


if __name__ == "__main__":
  main()
